sql:
SELECT section_id, capacity
FROM sections
WHERE capacity = (SELECT MAX(capacity) FROM sections);

external_knowledge:
- 'classes' can be interpreted as different courses;
- 'enrollment numbers' refer to the number of students registered for sections of a course;
- 'average enrollment numbers' refers to the average number of students per section across all sections of a course.

sql:
SELECT section_id, actual_registered, waitlist_actual
FROM sections
WHERE section_id = 1;

SELECT department_name
FROM departments
WHERE department_id NOT IN (
  SELECT DISTINCT department_id
  FROM courses
);
